// deepCopy creates a deep copy of a map or slice to prevent script modifications from affecting original data
func deepCopy(v interface{}) interface{} {
	switch val := v.(type) {
	case map[string]interface{}:
		copied := make(map[string]interface{}, len(val))
		for k, nestedVal := range val {
			copied[k] = deepCopy(nestedVal)
		}
		return copied
	case []interface{}:
		copied := make([]interface{}, len(val))
		for i, nestedVal := range val {
			copied[i] = deepCopy(nestedVal)
		}
		return copied
	// Basic types are immutable, return as-is
	case int, int32, int64, float32, float64, string, bool, nil:
		return val
	// Handle other common types if needed
	default:
		return val
	}
}

