	ctx, cancel := context.WithTimeout(context.Background(), maxExecutionTime)
	defer cancel()

	// Create deep copy of order to isolate script from original data
	copiedOrder := deepCopy(order).(map[string]interface{})
	if err := vm.Set("order", copiedOrder); err != nil {
		return 0.0, fmt.Errorf("failed to initialize order object: %w", err)
	}

	// Disable dangerous JavaScript built-ins to prevent code injection and unexpected behavior
	vm.Set("eval", goja.Undefined())
	vm.Set("Function", goja.Undefined())
	vm.Set("setTimeout", goja.Undefined())
	vm.Set("setInterval", goja.Undefined())
	vm.Set("require", goja.Undefined())

	// Execute the sandboxed script with context timeout handling
	var result goja.Value
	var runErr error

	executionDone := make(chan struct{})
	go func() {
		defer close(executionDone)
		result, runErr = vm.RunString(script)
	}()

	select {
	case <-executionDone:
		if runErr != nil {
			return 0.0, fmt.Errorf("script execution failed: %w", runErr)
		}
	case <-ctx.Done():
		// Interrupt the running script on timeout
